   160→        payment.status === PaymentStatus.CANCELED ||
   161→        payment.status === PaymentStatus.EXPIRED
   162→      ) {
   163→        return false;
   164→      }
   165→
   166→      await new Promise((resolve) => setTimeout(resolve, 1000));
   167→    }
