   921→function CryptoCtaButton({
   922→  phase,
   923→  isActive,
   924→  selectedCurrency,
   925→  onGenerate,
   926→  onRetry,
   927→}: {
   928→  phase: CryptoPhase["phase"];
   929→  isActive: boolean;
   930→  selectedCurrency: string;
   931→  onGenerate: (currency: string) => void;
   932→  onRetry: () => void;
   933→}) {
   934→  if (phase === "failed") {
   935→    return (
   936→      <button
   937→        type="button"
   938→        onClick={() => onGenerate(selectedCurrency)}
   939→        className="flex h-12 w-fit items-center justify-center self-center rounded-[4px] bg-[#021171] px-8 font-medium font-new-sans text-[#F5F3EF] text-base"
   940→      >
   941→        Try Again
   942→      </button>
   943→    );
   944→  }
   945→  if (isActive) {
   946→    return (
   947→      <button
   948→        type="button"
   949→        onClick={onRetry}
   950→        className="flex h-12 w-fit items-center justify-center self-center rounded-[4px] bg-[#021171] px-8 font-medium font-new-sans text-[#F5F3EF] text-base"
   951→      >
   952→        Reset Payment Address
   953→      </button>
   954→    );
   955→  }
   956→  if (phase === "generating") {
   957→    return (
   958→      <div className="flex h-12 items-center justify-center gap-2 self-center">
   959→        <svg className="h-4 w-4 animate-spin text-[#021171]" viewBox="0 0 24 24" fill="none" aria-hidden="true">
   960→          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
   961→          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
   962→        </svg>
   963→        <span className="font-new-sans text-[#44403C] text-sm">Generating address…</span>
   964→      </div>
   965→    );
   966→  }
   967→  return (
   968→    <button
   969→      type="button"
   970→      onClick={() => onGenerate(selectedCurrency)}
   971→      className="flex h-12 w-fit items-center justify-center self-center rounded-[4px] bg-[#021171] px-8 font-medium font-new-sans text-[#F5F3EF] text-base"
   972→    >
   973→      Generate Payment Address
   974→    </button>
   975→  );
   976→}
