  1002→function CryptoPaymentSection({
  1003→  cryptoPhase,
  1004→  amountCents,
  1005→  onGenerate,
  1006→  onRetry,
  1007→  onExpired,
  1008→}: CryptoPaymentSectionProps) {
  1009→  const [selectedCurrency, setSelectedCurrency] = useState<string>(CRYPTO_OPTIONS[0].value);
  1010→  const [copied, setCopied] = useState(false);
  1011→  const [timeLeft, setTimeLeft] = useState<string | null>(null);
  1012→  const [isExpired, setIsExpired] = useState(false);
  1013→
  1014→  const isActive =
  1015→    cryptoPhase.phase === "awaiting" || cryptoPhase.phase === "confirming";
  1016→  const checkout = isActive ? cryptoPhase.checkout : null;
  1017→
  1018→  const selectedOption =
  1019→    CRYPTO_OPTIONS.find((o) => o.value === selectedCurrency) ?? CRYPTO_OPTIONS[0];
  1020→
  1021→  // Display amount: use checkout crypto amount when available, else USD cents → stablecoin approx
  1022→  const displayAmount = checkout
  1023→    ? `${checkout.payAmount.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 6 })} ${checkout.payCurrency.toUpperCase()}`
  1024→    : `${(amountCents / 100).toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })} ${selectedOption.label}`;
  1025→
  1026→  const displaySubAmount = checkout
  1027→    ? `USD ${checkout.priceAmount.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
  1028→    : null;
  1029→
  1030→  useEffect(() => {
  1031→    const expiryDate = checkout?.expirationEstimateDate;
  1032→    if (!expiryDate) {
  1033→      setTimeLeft(null);
  1034→      setIsExpired(false);
  1035→      return;
  1036→    }
  1037→
  1038→    const update = () => {
  1039→      const diff = new Date(expiryDate).getTime() - Date.now();
  1040→      if (diff <= 0) {
  1041→        setTimeLeft(null);
  1042→        setIsExpired(true);
  1043→        return;
  1044→      }
  1045→      const minutes = Math.floor(diff / 60_000);
  1046→      const seconds = Math.floor((diff % 60_000) / 1000);
  1047→      setTimeLeft(`${minutes}:${seconds.toString().padStart(2, "0")}`);
  1048→    };
  1049→
  1050→    setIsExpired(false);
  1051→    update();
  1052→    const interval = setInterval(update, 1000);
  1053→    return () => clearInterval(interval);
  1054→  }, [checkout?.expirationEstimateDate]);
  1055→
  1056→  useEffect(() => {
  1057→    if (isExpired && isActive) {
  1058→      onExpired();
  1059→    }
  1060→  }, [isExpired, isActive, onExpired]);
  1061→
  1062→  async function handleCopyAddress() {
  1063→    if (!checkout?.payAddress) return;
  1064→    await navigator.clipboard.writeText(checkout.payAddress);
  1065→    setCopied(true);
  1066→    setTimeout(() => setCopied(false), 2000);
  1067→  }
  1068→
  1069→  const networkName = checkout
  1070→    ? checkout.payCurrency.replace("usdttrc20", "TRC20").replace("usdterc20", "ETH").replace("usdc", "ETH").toUpperCase() || selectedOption.network
