  1079→        </h2>
  1080→        <div className="flex items-baseline gap-1">
  1081→          {/* USDC icon */}
  1082→          <span className="inline-flex h-5 w-5 flex-shrink-0 items-center justify-center rounded-full bg-[#2775CA] font-bold text-[9px] text-white">$</span>
  1083→          <span className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">USDC</span>
  1084→        </div>
  1085→        <span className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">or</span>
  1086→        <div className="flex items-baseline gap-1">
  1087→          {/* USDT icon */}
  1088→          <span className="inline-flex h-5 w-5 flex-shrink-0 items-center justify-center rounded-full bg-[#26A17B] font-bold text-[9px] text-white">₮</span>
  1089→          <span className="font-light font-new-serif text-2xl text-[#44403C] leading-[120%]">USDT</span>
  1090→        </div>
  1091→      </div>
  1092→
  1093→      <div className="h-px bg-[#D6D3D1]" />
  1094→
  1095→      {/* Description + network icons */}
  1096→      <div className="flex flex-col gap-3">
  1097→        <p className="font-new-sans text-[#44403C] text-sm leading-[150%]">
  1098→          Select your preferred crypto asset to complete the buyback payment.
  1099→          Currently supporting stablecoins in multiple networks.
  1100→        </p>
  1101→        <div className="flex">
  1102→          {NETWORK_ICONS.map((icon, idx) => (
  1103→            <span
  1104→              key={icon.label}
  1105→              className="inline-flex h-8 w-8 flex-shrink-0 items-center justify-center rounded-full font-bold text-[9px] text-white"
  1106→              style={{ background: icon.bg, marginLeft: idx === 0 ? 0 : -4, zIndex: NETWORK_ICONS.length - idx }}
  1107→            >
  1108→              {icon.label}
  1109→            </span>
  1110→          ))}
  1111→        </div>
  1112→      </div>
  1113→
