  1059→
  1060→function CryptoPaymentSection({
  1061→  cryptoPhase,
  1062→  amountCents,
  1063→  onGenerate,
  1064→  onRetry,
  1065→  onExpired,
  1066→}: CryptoPaymentSectionProps) {
  1067→  const { data: currenciesData } = useNowPaymentsCurrencies();
  1068→  const cryptoOptions = (
  1069→    currenciesData?.currencies ?? ["usdttrc20", "usdc", "usdterc20"]
  1070→  ).map((code) => ({ value: code, ...getCurrencyMeta(code) }));
  1071→
